// 1. Прямое обращение к вебхуку через метод .first() - это самый стабильный путь в n8n
const inputData = $('Webhook: Incoming ChatApp').first().json.body;

const phone = inputData.phone || "";
const message = inputData.message || ""; // <--- ОБЯЗАТЕЛЬНО ОБЪЯВЛЯЕМ MESSAGE

// 2. Маскируем телефон
const maskedPhone = phone.toString().replace(/.(?=.{4})/g, '*');

// 3. Маскируем номера карт
const safeMessage = message.replace(/\b(?:\d[ -]*?){13,16}\b/g, '[CARD_REDACTED]');

// 4. Возвращаем результат
return {
  original_phone: phone,
  masked_phone: maskedPhone,
  safe_message: safeMessage,
  original_message: message
};

