let rawString = $input.item.json.output || $input.item.json.text || "";

try {
  let cleanString = rawString.toString()
    .replace(/```json/g, '').replace(/```/g, '').trim();

  const data = JSON.parse(cleanString);

  return {
    output: data.output || data.reply || "MANAGER",
    lead_score: data.lead_score || 0,
    lead_status: data.lead_status || "Cold",
    reason: data.reason || "No reason",
    source: data.source || "LLM"
  };
} catch (e) {
  // На случай системного сбоя возвращаем код вызова человека
  return { output: "MANAGER", lead_score: 0, lead_status: "Error" };
}

